css:
* { margin: 0; padding: 0; box-sizing: border-box; }
body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; background: #f8f9fa; color: #1a1a2e; }
nav { display: flex; align-items: center; justify-content: space-between; padding: 0 32px; height: 68px; background: white; border-bottom: 1px solid #e9ecef; position: sticky; top: 0; z-index: 100; box-shadow: 0 1px 8px rgba(0,0,0,0.06); }
.logo { font-size: 20px; font-weight: 800; }
.search { display: flex; align-items: center; gap: 10px; background: #f1f3f5; border-radius: 24px; padding: 10px 18px; width: 360px; }
.search input { border: none; background: transparent; font-size: 15px; outline: none; width: 100%; color: #1a1a2e; }
.nav-right { display: flex; gap: 12px; align-items: center; }
.nav-icon { border: none; background: #f1f3f5; border-radius: 20px; padding: 10px 16px; font-size: 14px; cursor: pointer; font-weight: 600; }
.cart-btn { border: none; background: #22c55e; color: white; border-radius: 20px; padding: 10px 20px; font-size: 14px; font-weight: 700; cursor: pointer; display: flex; align-items: center; gap: 8px; } .cart-btn span { background: white; color: #22c55e; border-radius: 50%; width: 20px; height: 20px; display: flex; align-items: center; justify-content: center; font-size: 12px; font-weight: 800; }
.layout { display: flex; gap: 0; min-height: calc(100vh - 68px); }
.sidebar { width: 240px; background: white; border-right: 1px solid #e9ecef; padding: 24px 20px; flex-shrink: 0; }
.sidebar h3 { font-size: 13px; font-weight: 700; color: #6b7280; letter-spacing: 1px; margin-bottom: 12px; margin-top: 24px; } .sidebar h3:first-child { margin-top: 0; }
.categories { display: flex; flex-direction: column; gap: 6px; }
.cat { width: 100%; text-align: left; padding: 10px 14px; border-radius: 10px; border: none; background: transparent; color: #6b7280; font-size: 14px; font-weight: 500; cursor: pointer; transition: all 0.2s; } .cat:hover { background: #f1f3f5; } .cat.active { background: #dcfce7; color: #15803d; font-weight: 700; }
.price-range input { width: 100%; accent-color: #22c55e; } .price-label { font-size: 13px; color: #6b7280; margin-top: 6px; }
.sort-select { width: 100%; padding: 10px 12px; border-radius: 10px; border: 1px solid #e9ecef; font-size: 14px; color: #1a1a2e; outline: none; background: white; cursor: pointer; }
.products-area { flex: 1; padding: 24px; }
.products-header { margin-bottom: 16px; font-size: 14px; color: #6b7280; }
.products-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(220px, 1fr)); gap: 20px; }
.product-card { background: white; border-radius: 16px; overflow: hidden; border: 1px solid #e9ecef; transition: all 0.2s; cursor: pointer; } .product-card:hover { transform: translateY(-4px); box-shadow: 0 12px 32px rgba(0,0,0,0.1); }
.product-img { height: 180px; display: flex; align-items: center; justify-content: center; font-size: 64px; background: linear-gradient(135deg, #f8f9fa, #e9ecef); }
.product-info { padding: 16px; }
.product-cat { font-size: 11px; font-weight: 700; color: #22c55e; letter-spacing: 1px; margin-bottom: 6px; }
.product-name { font-size: 15px; font-weight: 700; margin-bottom: 8px; line-height: 1.3; }
.product-price { font-size: 20px; font-weight: 900; color: #1a1a2e; margin-bottom: 12px; }
.add-btn { width: 100%; padding: 10px; border-radius: 10px; border: none; background: #22c55e; color: white; font-weight: 700; cursor: pointer; font-size: 14px; transition: background 0.2s; } .add-btn:hover { background: #16a34a; }
.cart-drawer { position: fixed; right: -380px; top: 0; width: 380px; height: 100vh; background: white; z-index: 200; transition: right 0.3s ease; padding: 24px; display: flex; flex-direction: column; box-shadow: -4px 0 20px rgba(0,0,0,0.1); }
.cart-drawer.open { right: 0; }
.cart-overlay { position: fixed; inset: 0; background: rgba(0,0,0,0.4); z-index: 199; display: none; }
.cart-overlay.open { display: block; }
.cart-header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 24px; } .cart-header h3 { font-size: 20px; font-weight: 800; } .cart-header button { width: 32px; height: 32px; border-radius: 50%; border: none; background: #f1f3f5; cursor: pointer; font-size: 16px; }
.cart-items { flex: 1; overflow-y: auto; }
.empty-cart { text-align: center; color: #9ca3af; padding: 40px; font-size: 15px; }
.cart-item { display: flex; gap: 12px; align-items: center; padding: 12px 0; border-bottom: 1px solid #f1f3f5; }
.cart-item-emoji { font-size: 32px; width: 48px; text-align: center; }
.cart-item-info { flex: 1; } .cart-item-info strong { display: block; font-size: 14px; margin-bottom: 2px; } .cart-item-info span { color: #22c55e; font-weight: 700; font-size: 15px; }
.cart-item-remove { background: none; border: none; color: #ef4444; cursor: pointer; font-size: 18px; }
.cart-total { display: flex; justify-content: space-between; align-items: center; padding: 16px 0; border-top: 1px solid #e9ecef; margin-top: 16px; font-size: 16px; } .cart-total strong { font-size: 22px; font-weight: 900; color: #22c55e; }
.checkout-btn { width: 100%; padding: 16px; border-radius: 14px; border: none; background: linear-gradient(135deg, #22c55e, #16a34a); color: white; font-size: 16px; font-weight: 800; cursor: pointer; margin-top: 8px; }

js:
const allProducts = [
  { id:1, name:'iPhone 15 Pro', price:45999, cat:'elektronik', emoji:'📱' },
  { id:2, name:'MacBook Air M2', price:38999, cat:'elektronik', emoji:'💻' },
  { id:3, name:'AirPods Pro', price:8499, cat:'aksesuar', emoji:'🎧' },
  { id:4, name:'Deri Ceket', price:3999, cat:'giyim', emoji:'🧥' },
  { id:5, name:'Apple Watch', price:14999, cat:'aksesuar', emoji:'⌚' },
  { id:6, name:'Sneaker Pro', price:2499, cat:'giyim', emoji:'👟' }
];
let cart = [], filteredProducts = [...allProducts], currentCat = 'all', maxPrice = 10000;
function render() {
  const grid = document.getElementById('products');
  const visible = filteredProducts.filter(p => p.price <= maxPrice * 1000);
  document.getElementById('product-count').textContent = visible.length + ' ürün';
  grid.innerHTML = visible.map(p => `
    <div class="product-card">
      <div class="product-img">${p.emoji}</div>
      <div class="product-info">
        <div class="product-cat">${p.cat.toUpperCase()}</div>
        <div class="product-name">${p.name}</div>
        <div class="product-price">₺${p.price.toLocaleString('tr')}</div>
        <button class="add-btn" onclick="addToCart(${p.id})">+ Sepete Ekle</button>
      </div>
    </div>
  `).join('');
}
function addToCart(id) {
  const p = allProducts.find(p => p.id === id);
  const existing = cart.find(c => c.id === id);
  if (existing) existing.qty++; else cart.push({...p, qty: 1});
  updateCart();
}
function removeFromCart(id) { cart = cart.filter(c => c.id !== id); updateCart(); }
function updateCart() {
  document.getElementById('cart-count').textContent = cart.reduce((s,c)=>s+c.qty,0);
  const total = cart.reduce((s,c)=>s+(c.price*c.qty),0);
  document.getElementById('cart-total').textContent = '₺' + total.toLocaleString('tr');
  const items = document.getElementById('cart-items');
  items.innerHTML = cart.length === 0 ? '<div class="empty-cart">Sepetiniz boş</div>' :
    cart.map(c => `<div class="cart-item"><span class="cart-item-emoji">${c.emoji}</span><div class="cart-item-info"><strong>${c.name} x${c.qty}</strong><span>₺${(c.price*c.qty).toLocaleString('tr')}</span></div><button class="cart-item-remove" onclick="removeFromCart(${c.id})">×</button></div>`).join('');
}
function toggleCart() { document.getElementById('cart-drawer').classList.toggle('open'); document.getElementById('cart-overlay').classList.toggle('open'); }
function filterCat(cat, btn) {
  currentCat = cat;
  document.querySelectorAll('.cat').forEach(b => b.classList.remove('active'));
  btn.classList.add('active');
  filteredProducts = cat === 'all' ? [...allProducts] : allProducts.filter(p => p.cat === cat);
  render();
}
function updatePrice(val) { maxPrice = val / 1000; document.getElementById('price-val').textContent = '₺' + parseInt(val).toLocaleString('tr'); render(); }
function sortProducts(val) {
  if (val === 'price-asc') filteredProducts.sort((a,b) => a.price - b.price);
  else if (val === 'price-desc') filteredProducts.sort((a,b) => b.price - a.price);
  else if (val === 'name') filteredProducts.sort((a,b) => a.name.localeCompare(b.name));
  else filteredProducts = currentCat === 'all' ? [...allProducts] : allProducts.filter(p => p.cat === currentCat);
  render();
}
render();
